// Ejecutar script de InforMessi
const { exec } = require('child_process');
const util = require('util');
const execPromise = util.promisify(exec);

const projectPath = '/home/sebastian-mesch-henriques/Escritorio/Personal/InforMessi';
const command = `cd ${projectPath} && source venv/bin/activate && export $(grep -v '^#' .env | grep -v '^$' | xargs) && bash scripts/daily-flow.sh`;

try {
  const { stdout, stderr } = await execPromise(command, {
    cwd: projectPath,
    shell: '/bin/bash',
    env: process.env
  });

  return {
    json: {
      success: true,
      stdout: stdout,
      stderr: stderr,
      message: 'Flujo ejecutado correctamente'
    }
  };
} catch (error) {
  return {
    json: {
      success: false,
      error: error.message,
      stdout: error.stdout || '',
      stderr: error.stderr || ''
    }
  };
}
